import java.io.*;

public class ExceptionHierarchy {

    static void readFile(String path) throws IOException {
        // Checked — compiler requires throws declaration or try-catch
        try (var r = new FileReader(path)) {
            System.out.println("Reading: " + path);
        }
    }

    static int divide(int a, int b) {
        // Unchecked — no throws declaration needed
        if (b == 0) throw new ArithmeticException("Cannot divide by zero");
        return a / b;
    }

    static void catchOrder(String input) {
        try {
            int n = Integer.parseInt(input);
            System.out.println(100 / n);
        } catch (NumberFormatException e) {   // SPECIFIC first
            System.out.println("Not a number: " + e.getMessage());
        } catch (ArithmeticException e) {     // SPECIFIC second
            System.out.println("Division error: " + e.getMessage());
        } catch (RuntimeException e) {        // GENERAL last
            System.out.println("Runtime: " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        System.out.println(divide(10, 2));
        try { divide(10, 0); }
        catch (ArithmeticException e) { System.out.println("Caught: " + e.getMessage()); }

        catchOrder("abc");
        catchOrder("0");
        catchOrder("5");

        try { readFile("/nonexistent.txt"); }
        catch (IOException e) { System.out.println("IO: " + e.getClass().getSimpleName()); }
    }
}

public class CustomExceptions {

    static class AppException extends Exception {
        private final String errorCode;
        AppException(String code, String msg) { super(msg); this.errorCode = code; }
        AppException(String code, String msg, Throwable cause) { super(msg, cause); this.errorCode = code; }
        public String getErrorCode() { return errorCode; }
    }

    static class ValidationException extends AppException {
        private final String field;
        ValidationException(String field, String msg) {
            super("VALIDATION_ERROR", "Field '" + field + "': " + msg);
            this.field = field;
        }
        public String getField() { return field; }
    }

    static class NotFoundException extends AppException {
        NotFoundException(String entity, Object id) {
            super("NOT_FOUND", entity + " not found: " + id);
        }
    }

    static class ConflictException extends AppException {
        ConflictException(String msg) { super("CONFLICT", msg); }
    }

    static class UserService {
        static void createUser(String name, int age) throws AppException {
            if (name == null || name.isBlank()) throw new ValidationException("name", "must not be blank");
            if (age < 0 || age > 150)           throw new ValidationException("age", "must be 0-150");
            if (name.equals("admin"))            throw new ConflictException("'admin' is reserved");
            System.out.println("Created: " + name);
        }
    }

    public static void main(String[] args) {
        for (String n : new String[]{null, "admin", "alice"}) {
            try {
                UserService.createUser(n, 25);
            } catch (ValidationException e) {
                System.out.println("Validation [" + e.getField() + "]: " + e.getMessage());
            } catch (ConflictException e) {
                System.out.println("Conflict: " + e.getMessage());
            } catch (AppException e) {
                System.out.println("AppError: " + e.getMessage());
            }
        }
    }
}

public class TryWithResources {

    static class Resource implements AutoCloseable {
        String name;
        Resource(String name) { System.out.println("Opening: " + name); this.name = name; }
        void use(boolean fail) {
            System.out.println("Using: " + name);
            if (fail) throw new RuntimeException("Use failed: " + name);
        }
        @Override public void close() {
            System.out.println("Closing: " + name);
            if (name.equals("BAD")) throw new RuntimeException("Close failed: " + name);
        }
    }

    public static void main(String[] args) {
        // Single resource — close always called
        System.out.println("=== Single ===");
        try (Resource r = new Resource("R1")) { r.use(false); }

        // Multiple — closed in REVERSE order
        System.out.println("\n=== Multiple ===");
        try (Resource outer = new Resource("OUTER"); Resource inner = new Resource("INNER")) {
            inner.use(false); outer.use(false);
        }

        // Suppressed exceptions
        System.out.println("\n=== Suppressed ===");
        try {
            try (Resource bad = new Resource("BAD")) {
                bad.use(true); // primary exception
            }  // close() also throws → suppressed!
        } catch (RuntimeException e) {
            System.out.println("Primary: " + e.getMessage());
            for (Throwable s : e.getSuppressed())
                System.out.println("Suppressed: " + s.getMessage());
        }
    }
}

