import java.io.*;

public class ExceptionChaining {

    static class AppException extends RuntimeException {
        final String code;
        AppException(String code, String msg, Throwable cause) { super(msg, cause); this.code = code; }
    }

    static String loadData(String key) {
        try {
            if (key.equals("bad")) throw new FileNotFoundException("File not found: " + key);
            return "data_" + key;
        } catch (IOException e) {
            throw new AppException("IO_ERROR", "Failed to load: " + key, e); // chain
        }
    }

    public static void main(String[] args) {
        // Multi-catch
        for (String s : new String[]{"1", "abc", null, "0"}) {
            try {
                int n = Integer.parseInt(s);
                System.out.println(10 / n);
            } catch (NumberFormatException | ArithmeticException e) {
                System.out.println("Caught " + e.getClass().getSimpleName() + ": " + e.getMessage());
            } catch (NullPointerException e) {
                System.out.println("Null input!");
            }
        }

        // Exception chaining
        try {
            loadData("bad");
        } catch (AppException e) {
            System.out.println("AppException: " + e.getMessage());
            System.out.println("Caused by: " + e.getCause().getClass().getSimpleName());
        }

        // Re-throwing with context
        try {
            try { Integer.parseInt("xyz"); }
            catch (NumberFormatException e) {
                throw new IllegalStateException("Config 'xyz' is invalid", e);
            }
        } catch (IllegalStateException e) {
            System.out.println(e.getMessage() + " | root: " + e.getCause().getMessage());
        }
    }
}

import java.util.function.*;

public class ResultPattern {

    sealed interface Result<T> permits Result.Ok, Result.Err {
        record Ok<T>(T value) implements Result<T> {}
        record Err<T>(String code, String message) implements Result<T> {}

        static <T> Result<T> ok(T v) { return new Ok<>(v); }
        static <T> Result<T> err(String c, String m) { return new Err<>(c, m); }

        default <U> Result<U> map(Function<T, U> fn) {
            return switch (this) {
                case Ok<T>  ok  -> Result.ok(fn.apply(ok.value()));
                case Err<T> err -> Result.err(err.code(), err.message());
            };
        }
    }

    static Result<Integer> safeParseInt(String s) {
        try   { return Result.ok(Integer.parseInt(s)); }
        catch (NumberFormatException e) { return Result.err("PARSE", "Not a number: " + s); }
    }

    public static void main(String[] args) {
        for (String s : new String[]{"10", "abc"}) {
            var r = safeParseInt(s).map(n -> n * 2);
            switch (r) {
                case Result.Ok<Integer>  ok  -> System.out.println("OK: "  + ok.value());
                case Result.Err<Integer> err -> System.out.println("ERR: " + err.message());
            }
        }
    }
}

