import java.util.Optional;

public class Q6 {
    record Inner(String value) {}
    record Middle(Inner inner) {}
    record Outer(Middle middle) {}

    static String getNested1(Outer obj) {
        try { return obj.middle().inner().value(); }
        catch (NullPointerException e) { return "[null]"; }
    }
    static String getNested2(Outer obj) {
        return Optional.ofNullable(obj)
            .map(Outer::middle).map(Middle::inner).map(Inner::value).orElse("[null]");
    }
    public static void main(String[] args) {
        Outer full     = new Outer(new Middle(new Inner("found")));
        Outer noInner  = new Outer(new Middle(null));
        System.out.println(getNested1(full));    // found
        System.out.println(getNested1(noInner)); // [null]
        System.out.println(getNested2(full));    // found
        System.out.println(getNested2(new Outer(null))); // [null]
    }
}

