import java.util.concurrent.Callable;
import java.util.concurrent.atomic.AtomicInteger;

public class Q7 {
    public static <T> T retry(Callable<T> op, int maxAttempts, long baseDelayMs) throws Exception {
        RuntimeException last = null;
        for (int a = 1; a <= maxAttempts; a++) {
            try { return op.call(); }
            catch (RuntimeException e) {
                last = e;
                if (a < maxAttempts) Thread.sleep(baseDelayMs * (1L << (a - 1)));
            }
        }
        throw last;
    }
    public static void main(String[] args) throws Exception {
        AtomicInteger n = new AtomicInteger();
        String r = retry(() -> {
            int i = n.incrementAndGet();
            System.out.println("Attempt " + i);
            if (i < 3) throw new RuntimeException("fail");
            return "Success " + i;
        }, 5, 10);
        System.out.println(r);
    }
}

