import java.util.*;
import java.util.function.Predicate;

public class Q8 {
    static class AggregateException extends RuntimeException {
        List<String> errors;
        AggregateException(List<String> e) { super(String.join("; ", e)); errors = List.copyOf(e); }
        public List<String> getErrors() { return errors; }
    }
    static void validateAll(Map<String, String> fields, Map<String, Predicate<String>> rules) {
        List<String> errors = new ArrayList<>();
        for (var entry : fields.entrySet()) {
            Predicate<String> rule = rules.get(entry.getKey());
            if (rule != null && !rule.test(entry.getValue()))
                errors.add("'" + entry.getKey() + "' invalid");
        }
        if (!errors.isEmpty()) throw new AggregateException(errors);
    }
    public static void main(String[] args) {
        var fields = Map.of("name","","age","abc","email","valid@x.com");
        var rules  = Map.of(
            "name",  (Predicate<String>) s -> !s.isBlank(),
            "age",   (Predicate<String>) s -> s.matches("\\d+"),
            "email", (Predicate<String>) s -> s.contains("@")
        );
        try { validateAll(fields, rules); }
        catch (AggregateException e) { System.out.println("Errors: " + e.getErrors().size()); }
    }
}

