import java.util.function.Supplier;

public class Q12 {
    static class CircuitOpenException extends RuntimeException { CircuitOpenException(){super("OPEN");} }
    static class CircuitBreaker {
        enum State { CLOSED, OPEN, HALF_OPEN }
        State state=State.CLOSED; int failures=0; long openedAt=0;
        final int threshold; final long resetMs;
        CircuitBreaker(int t,long r){threshold=t;resetMs=r;}
        <T> T call(Supplier<T> s) {
            if (state==State.OPEN) {
                if (System.currentTimeMillis()-openedAt>=resetMs) state=State.HALF_OPEN;
                else throw new CircuitOpenException();
            }
            try {
                T r=s.get(); failures=0; state=State.CLOSED; return r;
            } catch(RuntimeException e) {
                if(++failures>=threshold){state=State.OPEN;openedAt=System.currentTimeMillis();}
                throw e;
            }
        }
    }
    public static void main(String[] args) {
        CircuitBreaker cb=new CircuitBreaker(2,50);
        for(int i=1;i<=4;i++){
            final int fi=i;
            try{cb.call(()->{if(fi<=2)throw new RuntimeException("fail");return "ok";});
                System.out.println("OK");
            }catch(CircuitOpenException e){System.out.println("OPEN");}
             catch(RuntimeException e){System.out.println("Fail "+fi);}
        }
    }
}

