import java.util.*;
import java.util.concurrent.*;

public class Q14 {
    static class AggregateException extends RuntimeException {
        List<Throwable> causes;
        AggregateException(List<Throwable> c){super(c.size()+" failed");causes=c;}
    }
    static List<String> runAllOrFail(List<Callable<String>> tasks) {
        List<CompletableFuture<String>> futures = new ArrayList<>();
        for (Callable<String> t : tasks)
            futures.add(CompletableFuture.supplyAsync(()->{
                try{return t.call();}catch(Exception e){throw new RuntimeException(e);}}));
        List<String> results=new ArrayList<>(); List<Throwable> fails=new ArrayList<>();
        for (CompletableFuture<String> f : futures)
            try{results.add(f.join());}catch(CompletionException e){fails.add(e.getCause());}
        if (!fails.isEmpty()) throw new AggregateException(fails);
        return results;
    }
    public static void main(String[] args) {
        try {
            runAllOrFail(List.of(()->"A",()->"B",()->"C")).stream().sorted().forEach(System.out::println);
        } catch(AggregateException e){System.out.println("Failed: "+e.getMessage());}
        try {
            runAllOrFail(List.of(()->"ok",()->{throw new Exception("t2");},()->{throw new Exception("t3");}));
        } catch(AggregateException e){System.out.println(e.getMessage());}
    }
}

