import java.util.*;

public class Q16 {
    interface Step { String name(); void execute() throws Exception; void rollback(); }
    static void executeTransaction(List<Step> steps) throws Exception {
        Deque<Step> done = new ArrayDeque<>(); Exception primary = null;
        for (Step s : steps) {
            try { s.execute(); done.push(s); }
            catch (Exception e) { primary = e; break; }
        }
        if (primary != null) {
            while (!done.isEmpty()) {
                try { done.pop().rollback(); }
                catch (RuntimeException re) { primary.addSuppressed(re); }
            }
            throw primary;
        }
    }
    public static void main(String[] args) throws Exception {
        List<Step> steps = List.of(
            makeStep("create",false,false), makeStep("email",false,false),
            makeStep("charge",true,false),  makeStep("ship",false,false));
        try { executeTransaction(steps); }
        catch(Exception e) {
            System.out.println("Primary: "+e.getMessage());
            for(Throwable s:e.getSuppressed()) System.out.println("Suppressed: "+s.getMessage());
        }
    }
