import java.util.*;

public class Q18 {
    public static List<String> filteredStackTrace(Throwable t, String filter) {
        List<String> r = new ArrayList<>();
        r.add(t.getClass().getName()+": "+t.getMessage());
        for (StackTraceElement e : t.getStackTrace())
            if (e.getClassName().contains(filter))
                r.add("  at "+e.getClassName()+"."+e.getMethodName()+"("+e.getFileName()+":"+e.getLineNumber()+")");
        if (t.getCause()!=null){ r.add("Caused by:"); r.addAll(filteredStackTrace(t.getCause(),filter)); }
        return r;
    }
    static void inner(){throw new RuntimeException("inner");}
    static void outer(){try{inner();}catch(RuntimeException e){throw new RuntimeException("outer",e);}}
    public static void main(String[] args){
        try{outer();}catch(RuntimeException e){
            filteredStackTrace(e,"Q18").forEach(System.out::println);
        }
    }
