import java.util.*;
import java.util.function.Function;

public class Q20 {
    record Response(int status, String body){
        public String toString(){return status+": "+body;}
    }
    static class GlobalExceptionHandler {
        private final Map<Class<?>, Function<Exception, Response>> handlers = new LinkedHashMap<>();
        <E extends Exception> void register(Class<E> type, Function<E, Response> h){
            handlers.put(type, e -> h.apply(type.cast(e)));
        }
        Response handle(Exception e) {
            Class<?> clazz = e.getClass();
            while (clazz != null) {
                Function<Exception, Response> h = handlers.get(clazz);
                if (h != null) return h.apply(e);
                clazz = clazz.getSuperclass();
