        h.register(NFE.class, e->new Response(404,e.getMessage()));
        h.register(RuntimeException.class, e->new Response(500,"Runtime: "+e.getMessage()));
        Exception[] exs={new VE("email","bad format"),new NFE("User not found"),new RuntimeException("crash")};
